#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < Q; i++) {
        int type;
        scanf("%d", &type);
        if (type == 1) {
            int l, r;
            scanf("%d %d", &l, &r);
            int S[r - l + 1];
            int k = 0;
            for (int j = l - 1; j < r; j++) {
                S[k++] = A[j];
            }
            qsort(S, k, sizeof(int), compare);
            int product = 1;
            for (int j = 0; j < k; j++) {
                product *= S[j];
            }
            printf("%d\n", product);
        } else if (type == 2) {
            int x, y;
            scanf("%d %d", &x, &y);
            A[x - 1] = y;
        } else if (type == 3) {
            int x;
            scanf("%d", &x);
            for (int j = x - 1; j < N - 1; j++) {
                A[j] = A[j + 1];
            }
            N--;
        } else if (type == 4) {
            int z, y;
            scanf("%d %d", &z, &y);
            for (int j = N; j > z - 1; j--) {
                A[j] = A[j - 1];
            }
            A[z - 1] = y;
            N++;
        } else if (type == 5) {
            int l, r;
            scanf("%d %d", &l, &r);
            int count = 0;
            int seen[r - l + 1];
            memset(seen, 0, sizeof(seen));
            for (int j = l - 1; j < r; j++) {
                if (!seen[A[j]]) {
                    seen[A[j]] = 1;
                    count++;
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

