import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        for (int i = 0; i < Q; i++) {
            int type = sc.nextInt();
            if (type == 1) {
                int l = sc.nextInt();
                int r = sc.nextInt();
                int[] S = new int[r - l + 1];
                int k = 0;
                for (int j = l - 1; j < r; j++) {
                    S[k++] = A[j];
                }
                Arrays.sort(S);
                long product = 1;
                for (int j = 0; j < k; j++) {
                    product *= S[j];
                }
                System.out.println(product);
            } else if (type == 2) {
                int x = sc.nextInt();
                int y = sc.nextInt();
                A[x - 1] = y;
            } else if (type == 3) {
                int x = sc.nextInt();
                for (int j = x - 1; j < N - 1; j++) {
                    A[j] = A[j + 1];
                }
                N--;
            } else if (type == 4) {
                int z = sc.nextInt();
                int y = sc.nextInt();
                for (int j = N; j > z - 1; j--) {
                    A[j] = A[j - 1];
                }
                A[z - 1] = y;
                N++;
            } else if (type == 5) {
                int l = sc.nextInt();
                int r = sc.nextInt();
                int count = 0;
                boolean[] seen = new boolean[r - l + 1];
                for (int j = l - 1; j < r; j++) {
                    if (!seen[A[j]]) {
                        seen[A[j]] = true;
                        count++;
                    }
                }
                System.out.println(count);
            }
        }
    }
}

