const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(Number);
}

let [N, Q] = nextInts();
let A = nextInts();

for (let i = 0; i < Q; i++) {
    let type = nextInt();
    if (type === 1) {
        let [l, r] = nextInts();
        let S = A.slice(l-1, r).sort((a, b) => a - b);
        let product = 1;
        for (let num of S) {
            product *= num;
        }
        console.log(product);
    } else if (type === 2) {
        let [x, y] = nextInts();
        A[x-1] = y;
    } else if (type === 3) {
        let x = nextInt();
        A = A.slice(0, x-1).concat(A.slice(x));
    } else if (type === 4) {
        let [z, y] = nextInts();
        A = A.slice(0, z).concat([y], A.slice(z));
    } else if (type === 5) {
        let [l, r] = nextInts();
        let count = new Set(A.slice(l-1, r)).size;
        console.log(count);
    }
}
